from collections import defaultdict, deque

def topological_sort(n, edges):
    in_degree = [0] * (n + 1)
    graph = defaultdict(list)

    for u, v in edges:
        graph[u].append(v)
        in_degree[v] += 1

    queue = deque([i for i in range(1, n + 1) if in_degree[i] == 0])
    topo_order = []

    while queue:
        node = queue.popleft()
        topo_order.append(node)
        for neighbor in graph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    return topo_order

def solve_test_case(n, edges):
    topo_order = topological_sort(n, edges)
    closed_spots = set()

    for node in topo_order:
        for neighbor in graph[node]:
            if neighbor in topo_order and node < neighbor:
                closed_spots.add(node)
            elif node in topo_order and neighbor < node:
                closed_spots.add(neighbor)

    return sorted(closed_spots)

